import { PRContext, Finding, Review, FileChange } from '../types';
import { CacheStorage } from './storage';
import { logger } from '../utils/logger';
import { execFileSync } from 'child_process';

export interface IncrementalCacheData {
  prNumber: number;
  lastReviewedCommit: string;
  timestamp: number;
  findings: Finding[];
  reviewSummary: string;
  schemaVersion?: number;
  baseSha?: string;
  compatibilityKey?: string;
  expiresAt?: number;
}

export interface IncrementalChangeSet {
  files: FileChange[];
  invalidatedPaths: string[];
  canReusePreviousFindings: boolean;
}

export interface IncrementalStoragePort {
  read(key: string): Promise<string | null>;
  write(key: string, value: string): Promise<void>;
}

export interface IncrementalConfig {
  enabled: boolean;
  cacheTtlDays: number;
  compatibilityKey?: string;
  requireCompatibleSnapshot?: boolean;
}

export class IncrementalReviewer {
  private static readonly CACHE_KEY_PREFIX = 'incremental-review-pr-';
  private static readonly DEFAULT_TTL_DAYS = 7;
  private static readonly MS_PER_DAY = 24 * 60 * 60 * 1000;

  constructor(
    private readonly storage: IncrementalStoragePort = new CacheStorage(),
    private readonly config: IncrementalConfig = {
      enabled: true,
      cacheTtlDays: 7,
    },
    private readonly repositoryPath = process.cwd()
  ) {}

  /**
   * Check if incremental review should be used for this PR
   */
  async shouldUseIncremental(pr: PRContext): Promise<boolean> {
    if (!this.config.enabled) {
      logger.debug('Incremental review disabled by configuration');
      return false;
    }

    const lastReview = await this.getLastReview(pr.number);
    if (!lastReview) {
      logger.debug('No previous review found, running full review');
      return false;
    }

    if (this.config.requireCompatibleSnapshot) {
      if (
        lastReview.schemaVersion !== 1 ||
        lastReview.baseSha !== pr.baseSha ||
        !this.config.compatibilityKey ||
        lastReview.compatibilityKey !== this.config.compatibilityKey ||
        !lastReview.expiresAt ||
        lastReview.expiresAt <= Date.now()
      ) {
        logger.info(
          'Hosted incremental snapshot is incompatible or expired; running full review'
        );
        return false;
      }
    }

    // Check if cache is expired
    const ageMs = Date.now() - lastReview.timestamp;
    const ttlMs = this.config.cacheTtlDays * IncrementalReviewer.MS_PER_DAY;
    if (ageMs > ttlMs) {
      const ageMinutes = Math.round(ageMs / 1000 / 60);
      logger.debug(
        `Cache expired (age: ${ageMinutes} minutes, TTL: ${this.config.cacheTtlDays} days)`
      );
      return false;
    }

    // Check if the commit is still reachable
    if (lastReview.lastReviewedCommit === pr.headSha) {
      logger.debug('PR head SHA unchanged since last review');
      return false; // No changes, skip review entirely
    }

    logger.info(
      `Incremental review available from ${lastReview.lastReviewedCommit.substring(0, 7)} to ${pr.headSha.substring(0, 7)}`
    );
    return true;
  }

  /**
   * Get the last review data for a PR
   */
  async getLastReview(prNumber: number): Promise<IncrementalCacheData | null> {
    const key = this.buildCacheKey(prNumber);
    const raw = await this.storage.read(key);
    if (!raw) return null;

    try {
      const data = JSON.parse(raw) as IncrementalCacheData;
      return data;
    } catch (error) {
      logger.warn('Failed to parse incremental cache', error as Error);
      return null;
    }
  }

  /**
   * Save review data for incremental updates
   */
  async saveReview(pr: PRContext, review: Review): Promise<void> {
    const key = this.buildCacheKey(pr.number);
    const timestamp = Date.now();
    const data: IncrementalCacheData = {
      prNumber: pr.number,
      lastReviewedCommit: pr.headSha,
      timestamp,
      findings: review.findings,
      reviewSummary: review.summary,
      schemaVersion: 1,
      baseSha: pr.baseSha,
      ...(this.config.compatibilityKey
        ? { compatibilityKey: this.config.compatibilityKey }
        : {}),
      expiresAt:
        timestamp + this.config.cacheTtlDays * IncrementalReviewer.MS_PER_DAY,
    };

    await this.storage.write(key, JSON.stringify(data));
    logger.info(
      `Saved incremental review data for PR #${pr.number} at commit ${pr.headSha.substring(0, 7)}`
    );
  }

  /**
   * Validate that a string is a valid git SHA
   */
  private isValidSha(sha: string): boolean {
    return /^[a-f0-9]{40}$/i.test(sha);
  }

  /**
   * Get list of files changed since the last review
   */
  async getChangedFilesSince(
    pr: PRContext,
    lastCommit: string
  ): Promise<FileChange[]> {
    return (await this.getIncrementalChangeSet(pr, lastCommit)).files;
  }

  async getIncrementalChangeSet(
    pr: PRContext,
    lastCommit: string
  ): Promise<IncrementalChangeSet> {
    try {
      // Validate SHAs to prevent command injection
      if (!this.isValidSha(lastCommit)) {
        throw new Error(`Invalid commit SHA: ${lastCommit}`);
      }
      if (!this.isValidSha(pr.headSha)) {
        throw new Error(`Invalid PR head SHA: ${pr.headSha}`);
      }

      // Get the diff between last reviewed commit and current HEAD
      logger.debug(
        `Running git diff --name-status ${lastCommit.substring(0, 7)}..${pr.headSha.substring(0, 7)}`
      );

      let output: string;
      try {
        output = execFileSync(
          'git',
          ['diff', '--name-status', '-z', '-M', lastCommit, pr.headSha],
          {
            encoding: 'utf8',
            cwd: this.repositoryPath,
            timeout: 10000, // 10 second timeout
          }
        );
      } catch (error) {
        logger.warn(
          `Failed to get git diff: ${error instanceof Error ? error.message : String(error)}`
        );
        // If git diff fails, fall back to reviewing all files
        return {
          files: pr.files,
          invalidatedPaths: [],
          canReusePreviousFindings: false,
        };
      }

      const changedFiles: FileChange[] = [];
      const changedFileNames = new Set<string>();
      const invalidatedPaths = new Set<string>();
      const fields = output.split('\0');
      let index = 0;

      while (index < fields.length && fields[index]) {
        const status = fields[index++] ?? '';
        const previousFilename = /^[RC]/.test(status)
          ? fields[index++]
          : undefined;
        const filename = fields[index++] ?? '';
        if (!filename) continue;
        invalidatedPaths.add(filename);
        if (previousFilename) invalidatedPaths.add(previousFilename);

        // Find this file in the PR files list to get full details
        const prFile = pr.files.find(
          (f) =>
            f.filename === filename ||
            (previousFilename !== undefined &&
              f.previousFilename === previousFilename)
        );
        if (prFile && !changedFileNames.has(prFile.filename)) {
          changedFiles.push(prFile);
          changedFileNames.add(prFile.filename);
        } else {
          // File not in PR files (possibly deleted or outside PR scope)
          logger.debug(`File ${filename} in diff but not in PR files`);
        }
      }

      logger.info(
        `Found ${changedFiles.length} changed files since ${lastCommit.substring(0, 7)}`
      );
      return {
        files: changedFiles,
        invalidatedPaths: [...invalidatedPaths],
        canReusePreviousFindings: true,
      };
    } catch (error) {
      logger.error('Failed to get changed files from git diff', error as Error);
      logger.warn(
        `Falling back to full review (${pr.files.length} files) due to git diff failure`
      );
      // On error, return all PR files (fallback to full review)
      return {
        files: pr.files,
        invalidatedPaths: [],
        canReusePreviousFindings: false,
      };
    }
  }

  /**
   * Merge findings from previous review with new findings
   *
   * Strategy:
   * 1. Keep findings from unchanged files
   * 2. Remove findings from changed files (they'll be replaced by new review)
   * 3. Add new findings from current review
   */
  mergeFindings(
    previousFindings: Finding[],
    newFindings: Finding[],
    changedFiles: FileChange[],
    invalidatedPaths: readonly string[] = []
  ): Finding[] {
    const changedFilenames = new Set(
      changedFiles
        .flatMap((file) =>
          file.previousFilename
            ? [file.filename, file.previousFilename]
            : [file.filename]
        )
        .concat(invalidatedPaths)
    );

    // Keep findings from unchanged files
    const keptFindings = previousFindings.filter(
      (f) => !changedFilenames.has(f.file)
    );

    // Add new findings
    const merged = [...keptFindings, ...newFindings];

    logger.info(
      `Merged findings: ${keptFindings.length} kept from unchanged files, ` +
        `${newFindings.length} new from review, total ${merged.length}`
    );

    return merged;
  }

  /**
   * Generate incremental review summary
   */
  generateIncrementalSummary(
    previousSummary: string,
    newSummary: string,
    changedFiles: FileChange[],
    lastCommit: string,
    currentCommit: string
  ): string {
    const incrementalNote = `
## 🔄 Incremental Review

This is an incremental review covering changes from \`${lastCommit.substring(0, 7)}\` to \`${currentCommit.substring(0, 7)}\`.

**Files reviewed in this update:** ${changedFiles.length}
${changedFiles.map((f) => `- ${f.filename}`).join('\n')}

---

${newSummary}

<details>
<summary>Previous Review Summary</summary>

${previousSummary}

</details>
`;

    return incrementalNote;
  }

  private buildCacheKey(prNumber: number): string {
    return `${IncrementalReviewer.CACHE_KEY_PREFIX}${prNumber}`;
  }
}
